writes = [
    {'qid': 31, 'title': '定义学生类', 'desc': '定义 <code>Student</code> 类，要求：<br>1. 使用 <code>__init__</code> 初始化 <code>name</code> 和 <code>age</code>。<br>2. 定义 <code>introduce()</code> 方法，输出学生姓名和年龄。<br>3. 创建两个学生对象，分别调用 <code>introduce()</code>。', 'reference': '<span class="kw">class</span> Student:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, name, age):\n        <span class="cm"># self.name 表示当前对象自己的 name 属性。</span>\n        <span class="cm"># 外部传入的 name 会保存到当前对象中。</span>\n        <span class="kw">self</span>.name = name\n\n        <span class="cm"># self.age 表示当前对象自己的 age 属性。</span>\n        <span class="cm"># 每个对象都有自己独立的 age。</span>\n        <span class="kw">self</span>.age = age\n\n    <span class="kw">def</span> introduce(<span class="kw">self</span>):\n        <span class="cm"># self 指向调用 introduce 方法的对象。</span>\n        <span class="cm"># 如果 stu1 调用，self 就是 stu1。</span>\n        <span class="cm"># 如果 stu2 调用，self 就是 stu2。</span>\n        <span class="fn">print</span>(<span class="str">f"大家好，我叫{self.name}，今年{self.age}岁。"</span>)\n\n\n<span class="cm"># 创建第一个学生对象。</span>\nstu1 = Student(<span class="str">"张三"</span>, <span class="num">18</span>)\n\n<span class="cm"># 创建第二个学生对象。</span>\nstu2 = Student(<span class="str">"李四"</span>, <span class="num">20</span>)\n\n<span class="cm"># 两个对象分别调用同一个方法，但 self 指向不同对象。</span>\nstu1.introduce()\nstu2.introduce()'},
    {'qid': 32, 'title': '定义手机类并打印对象信息', 'desc': '定义 <code>Phone</code> 类，要求：<br>1. 使用 <code>__init__</code> 初始化 <code>brand</code> 和 <code>price</code>。<br>2. 定义 <code>call()</code> 方法，输出"某品牌手机正在打电话"。<br>3. 定义 <code>__str__()</code> 方法，打印对象时显示品牌和价格。<br>4. 创建两个手机对象并测试。', 'reference': '<span class="kw">class</span> Phone:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, brand, price):\n        <span class="cm"># 初始化手机品牌。</span>\n        <span class="kw">self</span>.brand = brand\n\n        <span class="cm"># 初始化手机价格。</span>\n        <span class="kw">self</span>.price = price\n\n    <span class="kw">def</span> call(<span class="kw">self</span>):\n        <span class="cm"># 使用对象自己的 brand 属性输出信息。</span>\n        <span class="fn">print</span>(<span class="str">f"{self.brand} 手机正在打电话。"</span>)\n\n    <span class="kw">def</span> __str__(<span class="kw">self</span>):\n        <span class="cm"># 当 print(对象) 时，会自动调用 __str__。</span>\n        <span class="cm"># 返回值必须是字符串。</span>\n        <span class="kw">return</span> <span class="str">f"手机品牌：{self.brand}，价格：{self.price} 元"</span>\n\n\nphone1 = Phone(<span class="str">"华为"</span>, <span class="num">4999</span>)\nphone2 = Phone(<span class="str">"小米"</span>, <span class="num">2999</span>)\n\n<span class="cm"># print 对象时，会触发 __str__，显示更友好的对象信息。</span>\n<span class="fn">print</span>(phone1)\n<span class="fn">print</span>(phone2)\n\n<span class="cm"># 调用对象方法。</span>\nphone1.call()\nphone2.call()'},
    {'qid': 33, 'title': '封装账号余额', 'desc': '定义 <code>Account</code> 类，要求：<br>1. 使用 <code>__init__</code> 初始化用户名和私有余额 <code>__balance</code>。<br>2. 定义 <code>get_balance()</code> 方法，返回余额。<br>3. 定义 <code>deposit(amount)</code> 方法，充值金额。<br>4. 创建对象并测试充值前后余额。', 'reference': '<span class="kw">class</span> Account:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, username, balance):\n        <span class="cm"># 普通属性：用户名可以正常访问。</span>\n        <span class="kw">self</span>.username = username\n\n        <span class="cm"># 私有属性：余额不希望类外部随意修改。</span>\n        <span class="cm"># 加双下划线后，类外部不能直接通过 对象.__balance 访问。</span>\n        <span class="kw">self</span>.__balance = balance\n\n    <span class="kw">def</span> get_balance(<span class="kw">self</span>):\n        <span class="cm"># 提供一个公开方法，用来安全读取私有余额。</span>\n        <span class="kw">return</span> <span class="kw">self</span>.__balance\n\n    <span class="kw">def</span> deposit(<span class="kw">self</span>, amount):\n        <span class="cm"># 充值前先判断金额是否合法。</span>\n        <span class="kw">if</span> amount &lt;= <span class="num">0</span>:\n            <span class="fn">print</span>(<span class="str">"充值金额必须大于 0"</span>)\n            <span class="kw">return</span>\n\n        <span class="cm"># 修改私有属性时，在类内部完成。</span>\n        <span class="kw">self</span>.__balance += amount\n        <span class="fn">print</span>(<span class="str">f"{self.username} 充值 {amount} 元成功，当前余额：{self.__balance} 元"</span>)\n\n\naccount = Account(<span class="str">"张三"</span>, <span class="num">100</span>)\n\n<span class="cm"># 通过 get_balance 安全读取余额。</span>\n<span class="fn">print</span>(<span class="str">"充值前余额："</span>, account.get_balance())\n\n<span class="cm"># 调用充值方法。</span>\naccount.deposit(<span class="num">50</span>)\n\n<span class="cm"># 再次查看余额。</span>\n<span class="fn">print</span>(<span class="str">"充值后余额："</span>, account.get_balance())'},
    {'qid': 34, 'title': '减肥案例升级版', 'desc': '定义 <code>Person</code> 类，要求：<br>1. 属性：<code>name</code>、<code>weight</code>。<br>2. <code>run()</code>：每次跑步体重减少 <code>0.5kg</code>。<br>3. <code>eat()</code>：每次吃饭体重增加 <code>1kg</code>。<br>4. 创建两个对象，验证两个人体重互不影响。', 'reference': '<span class="kw">class</span> Person:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, name, weight):\n        <span class="cm"># 姓名属性。</span>\n        <span class="kw">self</span>.name = name\n\n        <span class="cm"># 体重属性。</span>\n        <span class="cm"># 每个对象都有自己的 weight，互不影响。</span>\n        <span class="kw">self</span>.weight = weight\n\n    <span class="kw">def</span> run(<span class="kw">self</span>):\n        <span class="cm"># 跑步后，当前对象自己的体重减少 0.5。</span>\n        <span class="kw">self</span>.weight -= <span class="num">0.5</span>\n        <span class="fn">print</span>(<span class="str">f"{self.name} 跑步后体重为：{self.weight}kg"</span>)\n\n    <span class="kw">def</span> eat(<span class="kw">self</span>):\n        <span class="cm"># 吃饭后，当前对象自己的体重增加 1。</span>\n        <span class="kw">self</span>.weight += <span class="num">1</span>\n        <span class="fn">print</span>(<span class="str">f"{self.name} 吃饭后体重为：{self.weight}kg"</span>)\n\n\nxiaoming = Person(<span class="str">"小明"</span>, <span class="num">80</span>)\nxiaohong = Person(<span class="str">"小红"</span>, <span class="num">55</span>)\n\n<span class="cm"># 小明的行为只影响小明自己的体重。</span>\nxiaoming.run()\nxiaoming.eat()\n\n<span class="cm"># 小红的行为只影响小红自己的体重。</span>\nxiaohong.run()\n\n<span class="cm"># 打印结果可以看到两个对象的数据互不影响。</span>\n<span class="fn">print</span>(<span class="str">"小明最终体重："</span>, xiaoming.weight)\n<span class="fn">print</span>(<span class="str">"小红最终体重："</span>, xiaohong.weight)'},
    {'qid': 35, 'title': 'AI 工具调用额度', 'desc': '定义 <code>AiToolAccount</code> 类，模拟一个 AI 工具账号，要求：<br>1. 属性：<code>username</code>、私有属性 <code>__quota</code> 表示剩余调用次数。<br>2. <code>call_ai()</code>：每调用一次，额度减少 1。<br>3. 如果额度不足，提示"额度不足，请充值"。<br>4. <code>recharge(count)</code>：增加调用额度。<br>5. <code>get_quota()</code>：查看剩余额度。', 'reference': '<span class="kw">class</span> AiToolAccount:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, username, quota):\n        <span class="cm"># 用户名，表示当前 AI 工具账号是谁的。</span>\n        <span class="kw">self</span>.username = username\n\n        <span class="cm"># 私有属性：剩余调用次数。</span>\n        <span class="cm"># 不建议外部直接修改，避免额度被随意改成负数或异常值。</span>\n        <span class="kw">self</span>.__quota = quota\n\n    <span class="kw">def</span> call_ai(<span class="kw">self</span>):\n        <span class="cm"># 如果额度不足，不能继续调用。</span>\n        <span class="kw">if</span> <span class="kw">self</span>.__quota &lt;= <span class="num">0</span>:\n            <span class="fn">print</span>(<span class="str">"额度不足，请充值"</span>)\n            <span class="kw">return</span>\n\n        <span class="cm"># 每调用一次 AI，额度减少 1。</span>\n        <span class="kw">self</span>.__quota -= <span class="num">1</span>\n        <span class="fn">print</span>(<span class="str">f"{self.username} 调用 AI 成功，剩余额度：{self.__quota}"</span>)\n\n    <span class="kw">def</span> recharge(<span class="kw">self</span>, count):\n        <span class="cm"># 充值次数必须大于 0。</span>\n        <span class="kw">if</span> count &lt;= <span class="num">0</span>:\n            <span class="fn">print</span>(<span class="str">"充值次数必须大于 0"</span>)\n            <span class="kw">return</span>\n\n        <span class="cm"># 在类内部修改私有属性。</span>\n        <span class="kw">self</span>.__quota += count\n        <span class="fn">print</span>(<span class="str">f"充值成功，当前额度：{self.__quota}"</span>)\n\n    <span class="kw">def</span> get_quota(<span class="kw">self</span>):\n        <span class="cm"># 提供公开方法查看私有额度。</span>\n        <span class="kw">return</span> <span class="kw">self</span>.__quota\n\n\naccount = AiToolAccount(<span class="str">"关同学"</span>, <span class="num">2</span>)\n\naccount.call_ai()\naccount.call_ai()\naccount.call_ai()\n\naccount.recharge(<span class="num">3</span>)\n<span class="fn">print</span>(<span class="str">"当前剩余额度："</span>, account.get_quota())'},
    {'qid': 36, 'title': '烤地瓜增加重置功能', 'desc': '定义 <code>SweetPotato</code> 类，要求：<br>1. 属性：<code>cook_time</code>、<code>cook_state</code>、<code>condiments</code>。<br>2. <code>cook(time)</code>：累计烤制时间，并根据总时间更新状态。<br>3. <code>add_condiment(name)</code>：添加调料。<br>4. <code>reset()</code>：把时间恢复为 0，状态恢复为"生的"，调料清空。<br>5. 定义 <code>__str__()</code> 返回当前状态。', 'reference': '<span class="kw">class</span> SweetPotato:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>):\n        <span class="cm"># 烤制总时间，初始为 0。</span>\n        <span class="kw">self</span>.cook_time = <span class="num">0</span>\n\n        <span class="cm"># 当前状态，初始是生的。</span>\n        <span class="kw">self</span>.cook_state = <span class="str">"生的"</span>\n\n        <span class="cm"># 调料列表，初始为空。</span>\n        <span class="kw">self</span>.condiments = []\n\n    <span class="kw">def</span> cook(<span class="kw">self</span>, time):\n        <span class="cm"># 注意这里必须使用 +=。</span>\n        <span class="cm"># 因为烤制时间应该累计，而不是每次覆盖。</span>\n        <span class="kw">self</span>.cook_time += time\n\n        <span class="cm"># 根据累计时间更新状态。</span>\n        <span class="kw">if</span> <span class="num">0</span> &lt;= <span class="kw">self</span>.cook_time &lt; <span class="num">3</span>:\n            <span class="kw">self</span>.cook_state = <span class="str">"生的"</span>\n        <span class="kw">elif</span> <span class="num">3</span> &lt;= <span class="kw">self</span>.cook_time &lt; <span class="num">7</span>:\n            <span class="kw">self</span>.cook_state = <span class="str">"半生不熟"</span>\n        <span class="kw">elif</span> <span class="num">7</span> &lt;= <span class="kw">self</span>.cook_time &lt;= <span class="num">12</span>:\n            <span class="kw">self</span>.cook_state = <span class="str">"熟了"</span>\n        <span class="kw">else</span>:\n            <span class="kw">self</span>.cook_state = <span class="str">"糊了"</span>\n\n    <span class="kw">def</span> add_condiment(<span class="kw">self</span>, name):\n        <span class="cm"># append 用来给列表追加一个调料。</span>\n        <span class="kw">self</span>.condiments.append(name)\n\n    <span class="kw">def</span> reset(<span class="kw">self</span>):\n        <span class="cm"># 重置时间。</span>\n        <span class="kw">self</span>.cook_time = <span class="num">0</span>\n\n        <span class="cm"># 重置状态。</span>\n        <span class="kw">self</span>.cook_state = <span class="str">"生的"</span>\n\n        <span class="cm"># 清空调料。</span>\n        <span class="kw">self</span>.condiments = []\n\n    <span class="kw">def</span> __str__(<span class="kw">self</span>):\n        <span class="cm"># 返回对象当前状态，方便 print(对象)。</span>\n        <span class="kw">return</span> <span class="str">f"烤制时间：{self.cook_time}分钟，状态：{self.cook_state}，调料：{self.condiments}"</span>\n\n\npotato = SweetPotato()\npotato.cook(<span class="num">5</span>)\npotato.add_condiment(<span class="str">"辣椒面"</span>)\n<span class="fn">print</span>(potato)\n\npotato.reset()\n<span class="fn">print</span>(<span class="str">"重置后："</span>, potato)'},
    {'qid': 37, 'title': '综合案例 1：学生成绩管理', 'desc': '定义 <code>ScoreStudent</code> 类，要求：<br>1. 属性：<code>name</code>、私有属性 <code>__score</code>。<br>2. 分数必须在 <code>0-100</code> 之间。<br>3. <code>set_score(score)</code>：修改分数，非法分数不允许修改。<br>4. <code>get_score()</code>：返回当前分数。<br>5. <code>is_pass()</code>：判断是否及格。<br>6. <code>__str__()</code>：打印对象时显示学生姓名、分数、是否及格。<br>7. 创建至少两个学生对象测试。', 'reference': '<span class="kw">class</span> ScoreStudent:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, name, score):\n        <span class="cm"># 学生姓名。</span>\n        <span class="kw">self</span>.name = name\n\n        <span class="cm"># 私有分数属性。</span>\n        <span class="cm"># 为了保证分数始终合法，不让外部随便改。</span>\n        <span class="kw">self</span>.__score = <span class="num">0</span>\n\n        <span class="cm"># 初始化时也通过 set_score 进行校验。</span>\n        <span class="kw">self</span>.set_score(score)\n\n    <span class="kw">def</span> set_score(<span class="kw">self</span>, score):\n        <span class="cm"># 分数必须在 0 到 100 之间。</span>\n        <span class="kw">if</span> <span class="num">0</span> &lt;= score &lt;= <span class="num">100</span>:\n            <span class="kw">self</span>.__score = score\n        <span class="kw">else</span>:\n            <span class="fn">print</span>(<span class="str">"分数必须在 0-100 之间，本次修改无效"</span>)\n\n    <span class="kw">def</span> get_score(<span class="kw">self</span>):\n        <span class="cm"># 通过公开方法读取私有分数。</span>\n        <span class="kw">return</span> <span class="kw">self</span>.__score\n\n    <span class="kw">def</span> is_pass(<span class="kw">self</span>):\n        <span class="cm"># 分数大于等于 60 表示及格。</span>\n        <span class="kw">return</span> <span class="kw">self</span>.__score &gt;= <span class="num">60</span>\n\n    <span class="kw">def</span> __str__(<span class="kw">self</span>):\n        <span class="cm"># 根据 is_pass 的结果生成文字。</span>\n        result = <span class="str">"及格"</span> <span class="kw">if</span> <span class="kw">self</span>.is_pass() <span class="kw">else</span> <span class="str">"不及格"</span>\n        <span class="kw">return</span> <span class="str">f"学生：{self.name}，分数：{self.__score}，结果：{result}"</span>\n\n\nstu1 = ScoreStudent(<span class="str">"张三"</span>, <span class="num">88</span>)\nstu2 = ScoreStudent(<span class="str">"李四"</span>, <span class="num">50</span>)\n\n<span class="fn">print</span>(stu1)\n<span class="fn">print</span>(stu2)\n\n<span class="cm"># 尝试设置非法分数。</span>\nstu1.set_score(<span class="num">150</span>)\n<span class="fn">print</span>(stu1)\n\n<span class="cm"># 设置合法分数。</span>\nstu2.set_score(<span class="num">70</span>)\n<span class="fn">print</span>(stu2)'},
    {'qid': 38, 'title': '综合案例 2：AI 服务套餐账号', 'desc': '定义 <code>AiServicePlan</code> 类，模拟一个 AI 服务套餐账号，要求：<br>1. 属性：<code>username</code>、<code>plan_name</code>、私有属性 <code>__remain_tokens</code>。<br>2. <code>use_tokens(count)</code>：使用指定 token 数。<br>3. 如果 token 足够，扣减并提示剩余 token。<br>4. 如果 token 不足，提示"不足以完成本次调用"。<br>5. <code>upgrade_plan(new_plan, add_tokens)</code>：升级套餐并增加 token。<br>6. <code>get_remain_tokens()</code>：查看剩余 token。<br>7. <code>__str__()</code>：返回账号、套餐、剩余 token 信息。', 'reference': '<span class="kw">class</span> AiServicePlan:\n    <span class="kw">def</span> __init__(<span class="kw">self</span>, username, plan_name, remain_tokens):\n        <span class="cm"># 用户名。</span>\n        <span class="kw">self</span>.username = username\n\n        <span class="cm"># 套餐名称，例如 basic、pro、team。</span>\n        <span class="kw">self</span>.plan_name = plan_name\n\n        <span class="cm"># 私有属性：剩余 token 数。</span>\n        <span class="cm"># token 是大模型调用中常见的计量单位。</span>\n        <span class="kw">self</span>.__remain_tokens = remain_tokens\n\n    <span class="kw">def</span> use_tokens(<span class="kw">self</span>, count):\n        <span class="cm"># 使用 token 数必须大于 0。</span>\n        <span class="kw">if</span> count &lt;= <span class="num">0</span>:\n            <span class="fn">print</span>(<span class="str">"使用 token 数必须大于 0"</span>)\n            <span class="kw">return</span>\n\n        <span class="cm"># 如果剩余 token 不够，则不能扣减。</span>\n        <span class="kw">if</span> count &gt; <span class="kw">self</span>.__remain_tokens:\n            <span class="fn">print</span>(<span class="str">"不足以完成本次调用，请升级套餐或充值 token"</span>)\n            <span class="kw">return</span>\n\n        <span class="cm"># 扣减 token。</span>\n        <span class="kw">self</span>.__remain_tokens -= count\n        <span class="fn">print</span>(<span class="str">f"本次使用 {count} token，剩余 {self.__remain_tokens} token"</span>)\n\n    <span class="kw">def</span> upgrade_plan(<span class="kw">self</span>, new_plan, add_tokens):\n        <span class="cm"># 升级套餐名称。</span>\n        <span class="kw">self</span>.plan_name = new_plan\n\n        <span class="cm"># 增加 token 数。</span>\n        <span class="kw">self</span>.__remain_tokens += add_tokens\n        <span class="fn">print</span>(<span class="str">f"套餐升级为 {self.plan_name}，增加 {add_tokens} token"</span>)\n\n    <span class="kw">def</span> get_remain_tokens(<span class="kw">self</span>):\n        <span class="cm"># 提供公开方法查看私有 token。</span>\n        <span class="kw">return</span> <span class="kw">self</span>.__remain_tokens\n\n    <span class="kw">def</span> __str__(<span class="kw">self</span>):\n        <span class="cm"># 返回账号当前信息。</span>\n        <span class="kw">return</span> <span class="str">f"用户：{self.username}，套餐：{self.plan_name}，剩余 token：{self.__remain_tokens}"</span>\n\n\nplan = AiServicePlan(<span class="str">"小明"</span>, <span class="str">"basic"</span>, <span class="num">1000</span>)\n\n<span class="fn">print</span>(plan)\n\n<span class="cm"># 第一次调用，token 足够。</span>\nplan.use_tokens(<span class="num">300</span>)\n\n<span class="cm"># 第二次调用，token 不足。</span>\nplan.use_tokens(<span class="num">900</span>)\n\n<span class="cm"># 升级套餐并增加 token。</span>\nplan.upgrade_plan(<span class="str">"pro"</span>, <span class="num">3000</span>)\n\n<span class="cm"># 再次调用。</span>\nplan.use_tokens(<span class="num">900</span>)\n\n<span class="fn">print</span>(plan)\n<span class="fn">print</span>(<span class="str">"剩余 token："</span>, plan.get_remain_tokens())'},
]
